    const user = await fetchUser('1');
    expect(user).toEqual({ id: '1', name: 'Jane' });
  });

  it('should reject for invalid id', async () => {
    await expect(fetchUser('')).rejects.toThrow('Invalid user ID');
  });

  it('should reject with specific error type', async () => {
    await expect(processPayment(-1)).rejects.toThrowError(
      expect.objectContaining({
        message: 'Invalid amount',
        code: 'INVALID_AMOUNT',
      })
    );
  });
});

import { describe, it, expect } from 'vitest';
import { createUser } from './user.service';

describe('createUser', () => {
  describe('validation errors', () => {
    it('should throw on empty name', async () => {
      await expect(createUser({ name: '', email: 'a@b.com' }))
        .rejects.toThrow('Name is required');
    });

    it('should throw on invalid email', async () => {
      await expect(createUser({ name: 'Jane', email: 'not-email' }))
        .rejects.toThrow('Invalid email');
    });

    it('should throw on duplicate email', async () => {
      await createUser({ name: 'Jane', email: 'jane@test.com' });
      await expect(createUser({ name: 'Jane2', email: 'jane@test.com' }))
        .rejects.toThrow('Email already exists');
    });
  });

  describe('success', () => {
    it('should create valid user', async () => {
      const user = await createUser({ name: 'Jane', email: 'jane@new.com' });
      expect(user.id).toBeDefined();
    });
  });
});

import { describe, it, expect, vi } from 'vitest';
import type { Request, Response, NextFunction } from 'express';
import { authMiddleware } from './auth.middleware';

function mockRequest(overrides: Partial<Request> = {}): Partial<Request> {
  return { headers: {}, ...overrides };
}

function mockResponse(): Partial<Response> {
  const res: Partial<Response> = {};
  res.status = vi.fn().mockReturnValue(res);
  res.json = vi.fn().mockReturnValue(res);
  return res;
}

describe('authMiddleware', () => {
  it('should call next() with valid token', () => {
    const req = mockRequest({ headers: { authorization: 'Bearer valid-token' } });
    const res = mockResponse();
    const next = vi.fn();

    authMiddleware(req as Request, res as Response, next as NextFunction);
    expect(next).toHaveBeenCalledOnce();
    expect(next).toHaveBeenCalledWith();
  });

  it('should return 401 without token', () => {
    const req = mockRequest();
    const res = mockResponse();
    const next = vi.fn();

    authMiddleware(req as Request, res as Response, next as NextFunction);
    expect(res.status).toHaveBeenCalledWith(401);
    expect(next).not.toHaveBeenCalled();
  });
});

import { describe, it, expect } from 'vitest';
import { z } from 'zod';
import request from 'supertest';
import { app } from '../app';

const UserResponseSchema = z.object({
  id: z.string().uuid(),
  name: z.string(),
  email: z.string().email(),
  createdAt: z.string().datetime(),
});

const UsersListSchema = z.array(UserResponseSchema);

describe('API Contract: /api/users', () => {
  it('GET /api/users should match contract', async () => {
    const response = await request(app)
      .get('/api/users')
      .expect(200);

    const result = UsersListSchema.safeParse(response.body);
    expect(result.success).toBe(true);
  });

  it('POST /api/users should return created user', async () => {
    const response = await request(app)
      .post('/api/users')
      .send({ name: 'Jane', email: 'jane@test.com' })
      .expect(201);

    const result = UserResponseSchema.safeParse(response.body);
    expect(result.success).toBe(true);
  });
});

import { render, screen } from '@testing-library/react';
import userEvent from '@testing-library/user-event';
import { describe, it, expect } from 'vitest';
import { Counter } from './Counter';

describe('Counter', () => {
  it('should render initial count', () => {
    render(<Counter initialCount={5} />);
    expect(screen.getByText('Count: 5')).toBeInTheDocument();
  });

  it('should increment on button click', async () => {
    const user = userEvent.setup();
    render(<Counter initialCount={0} />);

    await user.click(screen.getByRole('button', { name: /increment/i }));
    expect(screen.getByText('Count: 1')).toBeInTheDocument();
  });

  it('should disable button at max', () => {
    render(<Counter initialCount={10} max={10} />);
    expect(screen.getByRole('button', { name: /increment/i })).toBeDisabled();
  });
});

import { describe, it, expect, vi, afterEach } from 'vitest';
import { getConfig } from './config';

describe('getConfig', () => {
  afterEach(() => {
    vi.unstubAllEnvs();
  });

  it('should use PORT from environment', () => {
    vi.stubEnv('PORT', '8080');
    vi.stubEnv('DATABASE_URL', 'postgres://localhost/test');
    vi.stubEnv('NODE_ENV', 'test');

    const config = getConfig();
    expect(config.port).toBe(8080);
    expect(config.databaseUrl).toBe('postgres://localhost/test');
  });

  it('should use default PORT when not set', () => {
    vi.stubEnv('DATABASE_URL', 'postgres://localhost/test');
    vi.stubEnv('NODE_ENV', 'test');
    delete process.env.PORT;

    const config = getConfig();
    expect(config.port).toBe(3000);
  });
});

