import { describe, it, expect } from 'vitest';
import { classify } from './classifier';

describe('classify', () => {
  it.each([
    { input: 0, expected: 'zero' },
    { input: 1, expected: 'positive' },
    { input: -1, expected: 'negative' },
    { input: 100, expected: 'positive' },
    { input: -100, expected: 'negative' },
  ])('classify($input) should return $expected', ({ input, expected }) => {
    expect(classify(input)).toBe(expected);
  });

  it.each([
    [3, 'Fizz'],
    [5, 'Buzz'],
    [15, 'FizzBuzz'],
    [7, '7'],
  ])('fizzBuzz(%i) should return %s', (input, expected) => {
    expect(fizzBuzz(input)).toBe(expected);
  });
});

import { describe, it, expect, vi } from 'vitest';
import { EventEmitter, once } from 'node:events';
import { JobProcessor } from './job-processor';

describe('JobProcessor', () => {
  it('should emit "completed" when job finishes', async () => {
    const processor = new JobProcessor();
    const completedPromise = once(processor, 'completed');

    processor.process({ id: '1', type: 'email' });

    const [result] = await completedPromise;
    expect(result).toEqual({ id: '1', status: 'done' });
  });

  it('should emit "error" on invalid job', async () => {
    const processor = new JobProcessor();
    const errorHandler = vi.fn();
    processor.on('error', errorHandler);

    processor.process({ id: '', type: '' });

    expect(errorHandler).toHaveBeenCalledWith(
      expect.objectContaining({ message: 'Invalid job' })
    );
  });

  it('should emit "progress" events', async () => {
    const processor = new JobProcessor();
    const events: number[] = [];
    processor.on('progress', (pct: number) => events.push(pct));

    await processor.process({ id: '1', type: 'report' });

    expect(events).toEqual([25, 50, 75, 100]);
  });
});

import { describe, it, expect, beforeAll, afterAll } from 'vitest';
import { WebSocketServer, WebSocket } from 'ws';
import { createWSServer } from './ws-server';

let wss: WebSocketServer;
let port: number;

beforeAll(async () => {
  wss = createWSServer();
  await new Promise<void>((resolve) => {
    wss.on('listening', () => {
      port = (wss.address() as { port: number }).port;
      resolve();
    });
  });
});

afterAll(() => {
  wss.close();
});

function connectClient(): Promise<WebSocket> {
  return new Promise((resolve, reject) => {
    const ws = new WebSocket(`ws://localhost:${port}`);
    ws.on('open', () => resolve(ws));
    ws.on('error', reject);
  });
}

describe('WebSocket Server', () => {
  it('should echo messages', async () => {
    const client = await connectClient();
    const messagePromise = new Promise<string>((resolve) => {
      client.on('message', (data) => resolve(data.toString()));
    });

    client.send('hello');
    const response = await messagePromise;
    expect(response).toBe('hello');
    client.close();
  });
});

import { describe, it, expect, beforeAll, afterAll } from 'vitest';
import autocannon from 'autocannon';
import { createServer } from 'node:http';
import { app } from '../app';

let server: ReturnType<typeof createServer>;
let baseUrl: string;

beforeAll(async () => {
  server = createServer(app);
  await new Promise<void>((resolve) => {
    server.listen(0, () => {
      const addr = server.address() as { port: number };
      baseUrl = `http://localhost:${addr.port}`;
      resolve();
    });
  });
});

afterAll(() => {
  server.close();
});

describe('Performance', () => {
  it('GET /api/health should handle 1000 req/s', async () => {
    const result = await autocannon({
      url: `${baseUrl}/api/health`,
      connections: 10,
      duration: 5,
      pipelining: 1,
    });

    expect(result.errors).toBe(0);
    expect(result.non2xx).toBe(0);
    expect(result.requests.average).toBeGreaterThan(1000);
    expect(result.latency.p99).toBeLessThan(100);
  }, 30_000);
});

