});

describe('User queries', () => {
  it('should create user with posts', async () => {
    const user = await prisma.user.create({
      data: {
        name: 'Jane',
        email: 'jane@test.com',
        posts: {
          create: [
            { title: 'First Post', content: 'Hello world' },
            { title: 'Second Post', content: 'More content' },
          ],
        },
      },
      include: { posts: true },
    });

    expect(user.posts).toHaveLength(2);
    expect(user.posts[0].title).toBe('First Post');
  });

  it('should find users with post count', async () => {
    await prisma.user.create({
      data: { name: 'Jane', email: 'jane@test.com', posts: { create: { title: 'Post', content: 'Content' } } },
    });

    const users = await prisma.user.findMany({
      include: { _count: { select: { posts: true } } },
    });

    expect(users[0]._count.posts).toBe(1);
  });
});

import { describe, it, expect } from 'vitest';
import { z } from 'zod';

const CreateUserSchema = z.object({
  name: z.string().min(2).max(100),
  email: z.string().email(),
  age: z.number().int().min(13).max(150).optional(),
  role: z.enum(['admin', 'editor', 'viewer']).default('viewer'),
});

describe('CreateUserSchema', () => {
  it('should accept valid input', () => {
    const result = CreateUserSchema.safeParse({
      name: 'Jane Doe',
      email: 'jane@example.com',
      age: 30,
    });
    expect(result.success).toBe(true);
    if (result.success) {
      expect(result.data.role).toBe('viewer');
    }
  });

  it('should reject invalid email', () => {
    const result = CreateUserSchema.safeParse({
      name: 'Jane',
      email: 'not-an-email',
    });
    expect(result.success).toBe(false);
    if (!result.success) {
      const emailError = result.error.issues.find(i => i.path[0] === 'email');
      expect(emailError).toBeDefined();
    }
  });

  it('should reject name too short', () => {
    const result = CreateUserSchema.safeParse({ name: 'J', email: 'j@test.com' });
    expect(result.success).toBe(false);
  });

  it('should reject underage', () => {
    const result = CreateUserSchema.safeParse({ name: 'Jane', email: 'j@test.com', age: 10 });
    expect(result.success).toBe(false);
  });
});
